const intent = $json.intent || '';
const params = $json.intentParams || {};
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY || '';

let endpoint, queryParams;

if (intent === 'youtube_search') {
  endpoint = 'https://www.googleapis.com/youtube/v3/search';
  queryParams = {
    part: 'snippet',
    q: params.query || $json.inputText || '',
    maxResults: params.max_results || 5,
    type: 'video',
    key: GOOGLE_API_KEY
  };
} else if (intent === 'youtube_download') {
  return [{ json: { ...$json, responseText: '\ud83c\udfa5 Video download is not supported directly. Use a tool like yt-dlp on your laptop via the local bridge.', success: true } }];
} else {
  return [{ json: { ...$json, responseText: 'Unknown YouTube intent: ' + intent, success: false } }];
}

return [{ json: { ...$json, apiEndpoint: endpoint, apiParams: queryParams } }];

const items = $json.items || [];
if (items.length === 0) {
  return [{ json: { ...$input.item.json, responseText: 'No videos found.', success: true } }];
}

let text = '\ud83c\udfac YouTube Results:\n\n';
items.forEach((item, i) => {
  const title = item.snippet?.title || 'Untitled';
  const channel = item.snippet?.channelTitle || 'Unknown';
  const videoId = item.id?.videoId;
  const url = videoId ? 'https://youtube.com/watch?v=' + videoId : '';
  text += `${i+1}. <b>${title}</b>\n   by ${channel}\n   ${url}\n\n`;
});

return [{ json: { ...$input.item.json, responseText: text, success: true } }];
